import{_ as n,C as E,o as a,c as l,a5 as t,b as s,w as o,a as i,E as A,a4 as B}from"./chunks/framework.gGRxziV4.js";const u=JSON.parse('{"title":"Menlo的教训","description":"","frontmatter":{},"headers":[],"relativePath":"02-上下文工程/04-Menlo的教训.md","filePath":"02-上下文工程/04-Menlo的教训.md","lastUpdated":1774181700000}'),h={name:"02-上下文工程/04-Menlo的教训.md"};function p(d,e,g,_,c,m){const r=E("Mermaid");return a(),l("div",null,[e[1]||(e[1]=t('<h1 id="menlo的教训" tabindex="-1">Menlo的教训 <a class="header-anchor" href="#menlo的教训" aria-label="Permalink to &quot;Menlo的教训&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 2 模块的第 4 章。</p></blockquote><p>一个真实项目的上下文工程之路——从微调 vs 上下文工程的关键决策，到 KV 缓存优化、文件系统跃迁的实战经验。</p><hr><h2 id="关键决策-微调-vs-上下文工程" tabindex="-1">关键决策：微调 vs 上下文工程 <a class="header-anchor" href="#关键决策-微调-vs-上下文工程" aria-label="Permalink to &quot;关键决策：微调 vs 上下文工程&quot;">​</a></h2><p>Menlo AI 面临所有 AI 产品团队启动时都会遇到的问题：花数周微调专属模型，还是基于前沿大模型敏捷地开展上下文工程？</p><p>把一位通才医生培养成专科专家有两条路径。<strong>微调</strong>是专科深造之路——用海量专业病例让模型专项学习，直接改变内部权重。模型把新技能内化为本能，但反馈周期以周为单位，一旦基础模型更新换代适应性很差。<strong>上下文工程</strong>是临床指南之路——不改变通才本身，每次工作时提供一套完美的临床指南。模型并非真正成为专家，但每次任务中都能表现得像专家。迭代快、门槛低、适应性强。</p><p>Menlo 选择上下文工程路线。对于绝大多数希望转型 AI 的团队，默认从上下文工程开始——迭代更快、门槛更低，能迅速构建产品原型并验证。</p><hr><h2 id="kv-缓存命中率-北极星指标" tabindex="-1">KV 缓存命中率：北极星指标 <a class="header-anchor" href="#kv-缓存命中率-北极星指标" aria-label="Permalink to &quot;KV 缓存命中率：北极星指标&quot;">​</a></h2><p>在多轮循环中 Agent 需要反复提交冗长且大部分重复的上下文，直接导致高延迟和高成本。Menlo 认为北极星指标应该是 KV 缓存命中率——这是生产级 Agent 最重要的单一指标。</p><p>LLM 处理文本时会把对前面每个 Token 的理解缓存下来。推理引擎利用前缀匹配技术：第一次调用完整计算前缀并缓存，第二次调用检测到开头一致直接加载缓存，只对新增内容做增量计算。</p><p>高缓存命中率意味着更快更便宜。输入 10000 Token，9000 命中缓存时，成本从 3 美分降到 0.57 美分——节省 81%。</p>',13)),(a(),s(B,null,{default:o(()=>[A(r,{id:"mermaid-37",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E9%A6%96%E6%AC%A1%E8%B0%83%E7%94%A8%5D%20--%3E%20B%5B%E5%AE%8C%E6%95%B4%E8%AE%A1%E7%AE%97%E5%89%8D%E7%BC%80%20Token%5D%0A%20%20%20%20B%20--%3E%20C%5B%E7%BC%93%E5%AD%98%20KV%20%E7%8A%B6%E6%80%81%5D%0A%20%20%20%20D%5B%E5%90%8E%E7%BB%AD%E8%B0%83%E7%94%A8%5D%20--%3E%20E%7B%E5%89%8D%E7%BC%80%E5%8C%B9%E9%85%8D%EF%BC%9F%7D%0A%20%20%20%20E%20--%3E%7C%E5%AE%8C%E5%85%A8%E5%8C%B9%E9%85%8D%7C%20F%5B%E7%9B%B4%E6%8E%A5%E5%8A%A0%E8%BD%BD%E7%BC%93%E5%AD%98%3Cbr%2F%3E%E5%8F%AA%E5%81%9A%E5%A2%9E%E9%87%8F%E8%AE%A1%E7%AE%97%5D%0A%20%20%20%20E%20--%3E%7C%E4%B8%8D%E5%8C%B9%E9%85%8D%7C%20G%5B%E9%87%8D%E6%96%B0%E8%AE%A1%E7%AE%97%E5%85%A8%E9%83%A8%3Cbr%2F%3E%E7%BC%93%E5%AD%98%E5%A4%B1%E6%95%88%5D%0A%20%20%20%20F%20--%3E%20H%5B%E6%88%90%E6%9C%AC%E9%99%8D%E4%BD%8E%2081%25%3Cbr%2F%3E%E5%BB%B6%E8%BF%9F%E5%A4%A7%E5%B9%85%E9%99%8D%E4%BD%8E%5D%0A%20%20%20%20G%20--%3E%20I%5B%E6%88%90%E6%9C%AC%E5%85%A8%E4%BB%B7%3Cbr%2F%3E%E5%BB%B6%E8%BF%9F%E9%AB%98%5D%0A%20%20%20%20style%20H%20fill%3A%234a9%0A%20%20%20%20style%20I%20fill%3A%23f66%0A"})]),fallback:o(()=>[...e[0]||(e[0]=[i(" Loading... ",-1)])]),_:1})),e[2]||(e[2]=t('<blockquote><p>💡 <strong>图解：</strong> KV 缓存命中率是生产级 Agent 的北极星指标——前缀一个字符变了，缓存就全废了。</p></blockquote><h3 id="五大黄金法则" tabindex="-1">五大黄金法则 <a class="header-anchor" href="#五大黄金法则" aria-label="Permalink to &quot;五大黄金法则&quot;">​</a></h3><ol><li><strong>开启与选型</strong>：选用支持高效 KV 缓存的推理框架（如 vLLM）</li><li><strong>保证会话保持</strong>：同一用户会话路由到同一工作进程</li><li><strong>保持前缀稳定</strong>：Prompt 前缀中任何一个字符变更都会导致缓存失效</li><li><strong>上下文只追加</strong>：最缓存友好的操作是在末尾追加，任何中间修改都是缓存杀手</li><li><strong>明确标记缓存断点</strong>：手动插入特殊标记告诉引擎前缀范围</li></ol><h3 id="f1-赛车-vs-全地形越野车" tabindex="-1">F1 赛车 vs 全地形越野车 <a class="header-anchor" href="#f1-赛车-vs-全地形越野车" aria-label="Permalink to &quot;F1 赛车 vs 全地形越野车&quot;">​</a></h3><p>通过固定 Prompt 前缀最大化 KV 缓存命中率（F1 赛车模式）追求极致低延迟低成本但扩展性差。动态选择上下文（全地形越野车模式）扩展性强但牺牲缓存复用。需要根据业务需求做合理架构选择。</p><hr><h2 id="文件系统即上下文" tabindex="-1">文件系统即上下文 <a class="header-anchor" href="#文件系统即上下文" aria-label="Permalink to &quot;文件系统即上下文&quot;">​</a></h2><p>现代大模型上下文窗口越来越大，但在真实 Agent 场景中常常不够用甚至成为负担——物理限制、性能衰减（Context Rot）、成本高昂。</p><p>上下文压缩的陷阱：任何不可逆的压缩都带来语义丢失风险。Agent 必须根据历史状态做预测时，你无法确定哪一步的 Observation 在十步之后仍然关键。</p><p>Menlo 的创新：<strong>不再依赖模型上下文来存储所有历史，而是将文件系统本身视为 Agent 的外部长期记忆。</strong> 标志着从内存上下文到外部语义存储的架构跃迁。</p><p>三大好处：文件系统存储空间几乎无穷，天然支持网页、PDF、代码库；存入的数据可长期保存并以结构化方式存储中间产物；大模型不再被动读上下文，而是被赋予工具主动操作文件系统——&quot;上下文&quot;的概念从 Token 窗口扩展成了 Agent 可以交互、可读可写的持久化世界。</p><h3 id="闪电大脑-无限硬盘" tabindex="-1">闪电大脑 + 无限硬盘 <a class="header-anchor" href="#闪电大脑-无限硬盘" aria-label="Permalink to &quot;闪电大脑 + 无限硬盘&quot;">​</a></h3><p>Transformer 模型强大但计算成本极高，新兴 SSM 架构（如 Mamba）速度极快但长距离记忆能力是短板。这恰好形成完美组合：SSM 作为闪电大脑高效处理当前任务，文件系统作为无限硬盘保真存储长期记忆。这是神经图灵机这个伟大梦想在现代技术下的真正实现。</p><hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>默认从上下文工程开始，迭代快门槛低适应性强</li><li>KV 缓存命中率是北极星指标，前缀稳定+只追加+会话保持</li><li>文件系统即上下文：从内存到外部语义存储的架构跃迁</li><li>闪电大脑+无限硬盘：SSM + 文件系统的黄金组合</li></ul><hr><p><strong>上一章</strong>: <a href="./03-动态上下文与实战.html">动态上下文与实战</a> | <strong>下一章</strong>: <a href="./05-长运行Agent.html">长运行Agent</a></p>',18))])}const D=n(h,[["render",p]]);export{u as __pageData,D as default};
